using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentServiceClient(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments") ?? new();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"/api/shipments/track/{trackingNumber}");
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<ShipmentDto>();
        return null;
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments/mine") ?? new();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentDto dto)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", dto);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>() ?? new();
    }

    public async Task UpdateStatusAsync(int id, string newStatus)
    {
        var response = await http.PutAsJsonAsync($"/api/shipments/{id}/status", newStatus);
        response.EnsureSuccessStatusCode();
    }
}
