namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerId { get; set; }
    public string? DispatcherId { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}

namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerId { get; set; }
}

namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetAllShipmentsAsync();
    Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<List<ShipmentDto>> GetMyShipmentsAsync();
    Task<ShipmentDto> CreateShipmentAsync(CreateShipmentDto dto);
    Task UpdateStatusAsync(int id, string newStatus);
}

public class CreateShipmentDto
{
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string? CustomerId { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentServiceClient(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments") ?? new();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"/api/shipments/track/{trackingNumber}");
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<ShipmentDto>();
        return null;
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments/mine") ?? new();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentDto dto)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", dto);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>() ?? new();
    }

    public async Task UpdateStatusAsync(int id, string newStatus)
    {
        var response = await http.PutAsJsonAsync($"/api/shipments/{id}/status", newStatus);
        response.EnsureSuccessStatusCode();
    }
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServiceServer(ApplicationDbContext db, IHttpContextAccessor httpContextAccessor) : IShipmentService
{
    private string? GetUserId() => httpContextAccessor.HttpContext?.User?.FindFirst(System.Security.Claims.ClaimTypes.NameIdentifier)?.Value;

    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments.Select(s => new ShipmentDto
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = s.Status.ToString(),
            CreatedAt = s.CreatedAt,
            EstimatedDelivery = s.EstimatedDelivery,
            CustomerId = s.CustomerId
        }).ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var s = await db.Shipments.FirstOrDefaultAsync(x => x.TrackingNumber == trackingNumber);
        if (s is null) return null;
        return new ShipmentDto
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = s.Status.ToString(),
            CreatedAt = s.CreatedAt,
            EstimatedDelivery = s.EstimatedDelivery,
            CustomerId = s.CustomerId
        };
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        var userId = GetUserId();
        return await db.Shipments
            .Where(s => s.CustomerId == userId)
            .Select(s => new ShipmentDto
            {
                Id = s.Id,
                TrackingNumber = s.TrackingNumber,
                Origin = s.Origin,
                Destination = s.Destination,
                Status = s.Status.ToString(),
                CreatedAt = s.CreatedAt,
                EstimatedDelivery = s.EstimatedDelivery,
                CustomerId = s.CustomerId
            }).ToListAsync();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = $"TRK{DateTime.UtcNow:yyyyMMddHHmmss}{Random.Shared.Next(1000, 9999)}",
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = ShipmentStatus.Pending,
            CreatedAt = DateTime.UtcNow,
            EstimatedDelivery = dto.EstimatedDelivery,
            CustomerId = dto.CustomerId,
            DispatcherId = GetUserId()
        };

        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();

        return new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status.ToString(),
            CreatedAt = shipment.CreatedAt,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerId = shipment.CustomerId
        };
    }

    public async Task UpdateStatusAsync(int id, string newStatus)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null && Enum.TryParse<ShipmentStatus>(newStatus, out var status))
        {
            shipment.Status = status;
            await db.SaveChangesAsync();
        }
    }
}

