arguments.file_text:
@page "/track"
@inject IShipmentService ShipmentService
@inject NavigationManager Navigation

<PageTitle>Track Shipment</PageTitle>

<h2>Track a Shipment</h2>

<div class="mb-3" style="max-width: 400px;">
    <label class="form-label">Tracking Number</label>
    <div class="input-group">
        <input type="text" class="form-control" @bind="trackingNumber" placeholder="e.g. TRK20250101001" />
        <button class="btn btn-primary" @onclick="Search">Search</button>
    </div>
</div>

@if (searched)
{
    @if (shipment is not null)
    {
        <div class="card mt-3" style="max-width: 500px;">
            <div class="card-body">
                <h5 class="card-title">@shipment.TrackingNumber</h5>
                <p><strong>Origin:</strong> @shipment.Origin</p>
                <p><strong>Destination:</strong> @shipment.Destination</p>
                <p><strong>Status:</strong> <span class="badge bg-info">@shipment.Status</span></p>
                <p><strong>Created:</strong> @shipment.CreatedAt.ToString("g")</p>
                @if (shipment.EstimatedDelivery.HasValue)
                {
                    <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.Value.ToString("d")</p>
                }
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning mt-3">Shipment not found.</div>
    }
}

@code {
    [SupplyParameterFromQuery(Name = "number")]
    public string? QueryNumber { get; set; }

    private string trackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool searched;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrWhiteSpace(QueryNumber))
        {
            trackingNumber = QueryNumber;
            await Search();
        }
    }

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        searched = true;
    }
}

@page "/my-shipments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>My Shipments</PageTitle>

<h2>My Shipments</h2>

<div class="mb-3" style="max-width: 300px;">
    <input type="text" class="form-control" placeholder="Filter by tracking number..." @bind="searchFilter" @bind:event="oninput" />
</div>

@if (shipments is null)
{
    <p>Loading...</p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="row">
        @foreach (var s in FilteredShipments)
