                         <select class="form-select form-select-sm" style="width: auto;"
                                 value="@s.Status"
                                 @onchange="(e) => UpdateStatus(s.Id, e.Value?.ToString() ?? s.Status)">
                             <option value="Pending">Pending</option>
                             <option value="PickedUp">Picked Up</option>
                             <option value="InTransit">In Transit</option>
                             <option value="OutForDelivery">Out For Delivery</option>
                             <option value="Delivered">Delivered</option>
                             <option value="Cancelled">Cancelled</option>
                         </select>
                     </td>
                 </tr>
             }
         </tbody>
     </table>
 }

 @code {
     private List<ShipmentDto>? shipments;
     private string statusFilter = string.Empty;
     private bool showNewForm;
     private CreateShipmentDto newShipment = new();
     private DateTime? estimatedDelivery;

     private IEnumerable<ShipmentDto> FilteredShipments =>
         shipments?.Where(s => string.IsNullOrEmpty(statusFilter) || s.Status == statusFilter) ?? Enumerable.Empty<ShipmentDto>();

     protected override async Task OnInitializedAsync()
     {
         shipments = await ShipmentService.GetAllShipmentsAsync();
     }

     private void ToggleNewForm() => showNewForm = !showNewForm;

     private async Task CreateShipment()
     {
         newShipment.EstimatedDelivery = estimatedDelivery;
         await ShipmentService.CreateShipmentAsync(newShipment);
         newShipment = new();
         estimatedDelivery = null;
         showNewForm = false;
         shipments = await ShipmentService.GetAllShipmentsAsync();
     }

     private async Task UpdateStatus(int id, string newStatus)
     {
         await ShipmentService.UpdateStatusAsync(id, newStatus);
         shipments = await ShipmentService.GetAllShipmentsAsync();
     }
 }

